    var maxResult = 0

    // Try all possible ways to assign each number to A, B, or C
    func backtrack(index: Int, xorA: Int64, andB: Int64, xorC: Int64, countA: Int, countB: Int, countC: Int) {
        if index == n {
            let total = xorA + andB + xorC
