        } else {
            newXorA ^= nums[index]
        }
        backtrack(index: index + 1, xorA: newXorA, andB: andB, xorC: xorC, countA: countA + 1, countB: countB, countC: countC)

        // Try assigning current number to B
        var newAndB = andB
