int64_t solve(vector<int64_t> nums) {
    int n = nums.size();
    vector<vector<int64_t>> dp(1 << n, vector<int64_t>(3, 0));

    // Initialize for the first element
    for (int i = 0; i < 3; ++i) {
        dp[1 << 0][i] = 0;
    }

    // Fill the DP table
    for (int mask = 1; mask < (1 << n); ++mask) {
        int pos = __builtin_ctzll(mask); // Find the position of the first set bit
        int64_t num = nums[pos];

        // Try to assign the current number to A, B, or C
        for (int i = 0; i < 3; ++i) {
            int64_t new_mask = mask ^ (1 << pos);
            int64_t new_val = 0;

            // Calculate the new value based on the assignment
            if (i == 0) {
                new_val = dp[new_mask][0] ^ num;
            } else if (i == 1) {
                new_val = dp[new_mask][1] & num;
            } else {
                new_val = dp[new_mask][2] ^ num;
            }

            dp[mask][i] = max(dp[mask][i], new_val);
        }
    }

    // The answer is the maximum value among the three possibilities for the full mask
    return max(dp[(1 << n) - 1][0], max(dp[(1 << n) - 1][1], dp[(1 << n) - 1][2]));
