func solve(nums: Array<Int64>): Int64 {
    // Check if the array is empty
    if nums.isEmpty {
        return 0
    }

    // Initialize the maximum value
    var maxVal = 0

    // Iterate over all possible ways to assign elements to A, B, C
    // We use a bitmask to represent the assignment of each element
    for mask in 0..<1 << nums.count {
        // Initialize the XOR values for A, B, C
        var xorA = 0, xorB = 0, xorC = 0
        // Initialize the AND value for B
        var andB = 0

        // Iterate over each element
        for i in 0..<nums.count {
            // Check which subsequence the element belongs to
            let bit = (mask >> i) & 1

            switch bit {
            case 0:
                // Element belongs to A
                xorA ^= nums[i]
            case 1:
                // Element belongs to B
                andB &= nums[i]
                xorB ^= nums[i]
            case 2:
                // Element belongs to C
                xorC ^= nums[i]
            default:
                // Invalid bit value
                break
            }
        }

        // Calculate the total value
        let total = xorA + andB + xorC

        // Update the maximum value
        if total > maxVal {
            maxVal = total
        }
    }

    return Int64(maxVal)
}
